在Java中，您可以使用Apache POI库来操作Excel文件，并实现将不同sheet的内容合并到一个sheet中，并新增一个值为合并前sheet名的列。以下是一个示例代码：

```java
import org.apache.poi.ss.usermodel.*;

import java.io.FileInputStream;
import java.io.FileOutputStream;
import java.io.IOException;

public class ExcelMergeSheets {
    public static void main(String[] args) {
        String filePath = "your_file.xlsx";

        try (Workbook workbook = WorkbookFactory.create(new FileInputStream(filePath))) {
            Sheet mergedSheet = workbook.createSheet("Merged Data");

            // 遍历每个sheet
            for (Sheet sheet : workbook) {
                // 获取sheet名
                String sheetName = sheet.getSheetName();

                // 遍历每一行
                for (Row sourceRow : sheet) {
                    // 创建新的行
                    Row targetRow = mergedSheet.createRow(mergedSheet.getLastRowNum() + 1);

                    // 遍历每个单元格
                    for (Cell sourceCell : sourceRow) {
                        // 创建新的单元格
                        Cell targetCell = targetRow.createCell(sourceCell.getColumnIndex(), sourceCell.getCellType());

                        // 复制单元格内容
                        switch (sourceCell.getCellType()) {
                            case STRING:
                                targetCell.setCellValue(sourceCell.getRichStringCellValue());
                                break;
                            case NUMERIC:
                                targetCell.setCellValue(sourceCell.getNumericCellValue());
                                break;
                            //...添加其他需要处理的单元格类型
                        }
                    }

                    // 在合并后的sheet的新行后添加sheet名的值
                    Cell sheetNameCell = targetRow.createCell(sourceRow.getLastCellNum(), CellType.STRING);
                    sheetNameCell.setCellValue(sheetName);
                }
            }

            // 保存合并后的结果到新的Excel文件
            try (FileOutputStream fileOut = new FileOutputStream("merged.xlsx")) {
                workbook.write(fileOut);
            }
